<template>
    <section>
        <div class="my-popups">
            <div class="modal d-block" style="background-color: rgba(0,0,0,0.5);">
                <div class="modal-dialog modal-dialog-centered modal-lg">
                    <div class="modal-content">
                        <div class="modal-header theme-primary partition-full d-flex">
                            <h4 class="modal-title">Attachments</h4>
                            <button type="button" class="close" @click="Cancel">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                        </div>
                        <div class="modal-body p-3">
                            <!-- Attachments List -->
                            <div v-if="attachments.length > 0">
                                <h5 class="mb-3">
                                    <em class="fa fa-paperclip me-2"></em>
                                    {{ attachments.length }} Attachment(s)
                                </h5>

                                <div class="row">
                                    <div v-for="(attachment, index) in attachments" :key="index"
                                        class="col-md-6 col-lg-3 mb-3">
                                        <div class="card h-100 border">
                                            <!-- Remove Button (top-right corner) -->
                                            <button type="button" class="btn-close btn-close-danger d-none"
                                                @click="removeAttachment(index)" style="" @mouseenter="e => e.target.style.opacity = '1'"
                                                @mouseleave="e => e.target.style.opacity = '0.8'">
                                                <em class="fa fa-times text-danger" style="font-size: 12px;"></em>
                                            </button>

                                            <div class="card-body d-flex flex-column">
                                                <!-- File Icon based on type -->
                                                <!-- <div class="text-center mb-2">
                                                    <em class="fa display-4" 
                                                        :class="getFileIconClass(attachment)"></em>
                                                </div> -->

                                                <div class='img-icons new text-center p-2 file-image doc-icon'
                                                    v-if="isImageFile(getFileExtension(attachment.fileName))">
                                                    <img
                                                        :src="attachment.filePath && attachment.filePath.trim() !== '' ? attachment.filePath : file.BlobUrl" />
                                                </div>
                                                <div class='img-icons new text-center mt-4' v-else>
                                                    <em :class="['fa fa-2x', getFileIconClass(getFileExtension(attachment.fileName))]"
                                                        :style="{ color: getFileIconColor(getFileExtension(attachment.fileName)) }">
                                                    </em>
                                                </div>

                                                <!-- File Name -->
                                                <h6 class="card-title text-truncate" :title="getFileName(attachment)">
                                                    {{ getFileName(attachment) }}
                                                </h6>

                                                <!-- File Size -->
                                                <small v-if="getFileSize(attachment) > 0" class="text-muted text-center mb-2">
                                                   {{ $t('Size') }}: {{ formatFileSize(getFileSize(attachment)) }}
                                                </small>

                                                <!-- File Type -->
                                                <!-- <span class="badge bg-secondary mb-auto">
                                                    {{ getFileType(attachment) }}
                                                </span> -->

                                                <!-- Actions -->
                                                <div class="mt-3 d-flex justify-content-center gap-1">
                                                    <!-- View Button - Icon Only -->
                                                    <button class="btn btn-sm btn-outline-primary p-2"
                                                        @click="viewAttachment(attachment)" title="View Attachment">
                                                        <em class="fa fa-eye"></em>
                                                    </button>

                                                    <!-- Download Button - Icon Only -->
                                                    <button class="btn btn-sm btn-outline-success p-2"
                                                        @click="downloadAttachment(attachment, index)"
                                                        title="Download Attachment">
                                                        <em class="fa fa-download"></em>
                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                <!-- Bulk Download -->
                                <!-- <div v-if="attachments.length > 1" class="mt-4 text-center">
                                    <button class="btn btn-primary" @click="downloadAllAttachments">
                                        <em class="fa fa-download me-1"></em>
                                        Download All Attachments
                                    </button>
                                </div> -->
                            </div>

                            <!-- No Attachments Message -->
                            <div v-else class="text-center p-5">
                                <em class="fa fa-paperclip fa-3x text-muted mb-3"></em>
                                <p class="text-muted">No attachments found</p>
                            </div>
                        </div>

                        <div class="modal-footer">
                            <button type="button" class="btn btn-danger" @click="Cancel">
                                <em class="fa fa-close pr-2"></em> Close
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <!-- Image Viewer Modal -->
        <div v-if="showImageViewer" class="my-popups">
            <div class="modal d-block" style="background-color: rgba(0,0,0,0.8);">
                <div class="modal-dialog modal-dialog-centered modal-xl">
                    <div class="modal-content">
                        <div class="modal-header bg-dark text-white">
                            <h5 class="modal-title">{{ currentImageName }}</h5>
                            <button type="button" class="close text-white" @click="closeImageViewer">
                                <em class="fa fa-times"></em>
                            </button>
                        </div>
                        <div class="modal-body text-center p-0">
                            <img :src="currentImageUrl" :alt="currentImageName" class="img-fluid"
                                style="max-height: 70vh;">
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>

<script>
export default {
    props: {
        attachmentFileData: {
            type: Object,
            required: true
        }
    },
    data() {
        return {
            isLoading: false,
            showImageViewer: false,
            currentImageUrl: '',
            currentImageName: '',
            attachments: []
        }
    },
    computed: {
        messageContent() {
            return this.attachmentFileData.content ||
                this.attachmentFileData.message_board_comment_title ||
                this.attachmentFileData.message_board_content ||
                '';
        }
    },
    created() {
        this.processAttachments();
    },
    methods: {
        processAttachments() {
            try {
                debugger
                const fileAttachments = this.attachmentFileData.file_attachments;

                if (Array.isArray(fileAttachments) && fileAttachments.length > 0) {
                    this.attachments = fileAttachments.map((attachment, index) => {
                        debugger
                        const fileName = attachment.message_board_file_name ||
                            attachment.file_name ||
                            attachment.fileName ||
                            `attachment-${index + 1}`;
                        const filePath = attachment.message_board_file_path ||
                            attachment.file_path ||
                            attachment.base64String ||
                            '';
                        let fileSize = 0;
                        if (attachment.fileSize) {
                            fileSize = parseInt(attachment.fileSize);
                        } else if (attachment.size) {
                            fileSize = parseInt(attachment.size);
                        }
                        const isBase64 = !!attachment.base64String ||
                            (typeof filePath === 'string' &&
                                (filePath.startsWith('data:') ||
                                    (filePath.length > 100 && /[A-Za-z0-9+/=]/.test(filePath))));

                        return {
                            fileName: fileName,
                            filePath: filePath,
                            fileSize: fileSize, 
                            fileType: this.getFileTypeFromName(fileName),
                            mimeType: attachment.attachement_mime ||
                                attachment.type ||
                                'application/octet-stream',
                            isBase64: isBase64,
                            originalIndex: index
                        };
                    });
                    console.log('Processed attachments:', this.attachments);
                } else {
                    this.attachments = [];
                    console.log('No attachments found');
                }
            } catch (error) {
                console.error('Error processing attachments:', error);
                this.attachments = [];
            }
        },
        getFileName(attachment) {
            return attachment.fileName || 'attachment';
        },

        getFileSize(attachment) {
            if (attachment.fileSize) {
                return parseInt(attachment.fileSize);
            }
            if (attachment.filePath && attachment.isBase64) {
                try {                   
                    const base64String = attachment.filePath;                  
                    const cleanBase64 = base64String.includes(',')
                        ? base64String.split(',')[1]
                        : base64String;
                    return Math.round((cleanBase64.length * 3) / 4);
                } catch (error) {
                    console.error('Error calculating base64 size:', error);
                    return 0;
                }
            }

            return 0;
        },

        getFileType(attachment) {
            return attachment.fileType || 'Unknown';
        },

        getFileTypeFromName(fileName) {
            if (!fileName) return 'Unknown';

            const extension = fileName.split('.').pop().toLowerCase();
            const typeMap = {              
                'jpg': 'Image', 'jpeg': 'Image', 'png': 'Image', 'gif': 'Image',
                'bmp': 'Image', 'svg': 'Image', 'webp': 'Image',             
                'pdf': 'PDF', 'doc': 'Word', 'docx': 'Word', 'txt': 'Text',
                'rtf': 'Rich Text', 'odt': 'Document',              
                'xls': 'Excel', 'xlsx': 'Excel', 'csv': 'CSV',               
                'ppt': 'PowerPoint', 'pptx': 'PowerPoint',             
                'zip': 'ZIP', 'rar': 'RAR', '7z': 'Archive',               
                'mp3': 'Audio', 'wav': 'Audio', 'mp4': 'Video', 'avi': 'Video'
            };

            return typeMap[extension] || extension.toUpperCase();
        },
        isImageFile(extension) {
            return ['jpg', 'jpeg', 'png'].includes(extension);
        },
        getFileExtension(filename) {
            if (!filename) return '';
            return filename.split('.').pop().toLowerCase();
        },
        getFileIconClass(extension) {
            const iconMap = {
                'doc': 'fa-file-word-o',
                'docx': 'fa-file-word-o',
                'pdf': 'fa-file-pdf-o',
                'mp4': 'fa-file-video-o',
                'jpg': 'fa-file-image-o',
                'jpeg': 'fa-file-image-o',
                'png': 'fa-file-image-o',
                'xlsx': 'fa-file-excel-o',
                'xls': 'fa-file-excel-o',
                'txt': 'fa-file-text-o'
            };
            return iconMap[extension] || 'fa-file-o';
        },
        getFileIconColor(extension) {
            const colorMap = {
                'doc': '#2b579a',
                'docx': '#2b579a',
                'pdf': '#dc2626',
                'mp4': '#7c3aed',
                'jpg': '#059669',
                'jpeg': '#059669',
                'xlsx': '#217346',
                'xls': '#217346',
                'txt': '#374151'
            };
            return colorMap[extension] || '#6b7280';
        },

        formatFileSize(bytes) {
            if (bytes === 0) return '0 Bytes';
            const k = 1024;
            const sizes = ['Bytes', 'KB', 'MB', 'GB'];
            const i = Math.floor(Math.log(bytes) / Math.log(k));
            return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
        },

        formatDateTime(datetime) {
            if (!datetime) return '';
            const date = new Date(datetime);
            return date.toLocaleString('en-US', {
                month: 'short',
                day: 'numeric',
                year: 'numeric',
                hour: '2-digit',
                minute: '2-digit'
            });
        },

        getInitials(name) {
            if (!name) return 'U';
            return name
                .split(' ')
                .map(n => n[0])
                .join('')
                .toUpperCase()
                .substring(0, 2);
        },
viewAttachment(attachment) {
    const fileType = this.getFileType(attachment).toLowerCase();
    const fileName = this.getFileName(attachment);
    let fileUrl = '';

    if (attachment.isBase64) {
        const mimeType = attachment.mimeType || 'application/octet-stream';
        const byteCharacters = atob(attachment.filePath);
        const byteNumbers = new Array(byteCharacters.length);

        for (let i = 0; i < byteCharacters.length; i++) {
            byteNumbers[i] = byteCharacters.charCodeAt(i);
        }

        const byteArray = new Uint8Array(byteNumbers);
        const blob = new Blob([byteArray], { type: mimeType });

        fileUrl = URL.createObjectURL(blob);
    } else if (attachment.filePath) {
        fileUrl = attachment.filePath;
    }

    if (!fileUrl) {
        alert("File not available");
        return;
    }

    // Image preview
    if (fileType.includes('image')) {
        this.currentImageUrl = fileUrl;
        this.currentImageName = fileName;
        this.showImageViewer = true;
    }

    // PDF preview
    else if (fileType.includes('pdf')) {
        window.open(fileUrl, "_blank");
    }

    // Word / Excel / PPT preview using Office Viewer
    else if (
        fileType.includes('word') ||
        fileType.includes('excel') ||
        fileType.includes('spreadsheet') ||
        fileType.includes('presentation') ||
        fileName.endsWith('.doc') ||
        fileName.endsWith('.docx') ||
        fileName.endsWith('.xls') ||
        fileName.endsWith('.xlsx') ||
        fileName.endsWith('.ppt') ||
        fileName.endsWith('.pptx')
    ) {
        const officeViewer = `https://view.officeapps.live.com/op/view.aspx?src=${encodeURIComponent(fileUrl)}`;
        window.open(officeViewer, "_blank");
    }

    // Other files
    else {
        window.open(fileUrl, "_blank");
    }
},
        async downloadAttachment(attachment) {            
            try {  
                if (attachment.isBase64) {
                    await this.downloadBase64File(attachment);
                } else if (attachment.filePath) {
                    await this.downloadFromUrl(attachment);
                } else {
                    console.error('No valid file data found for attachment:', attachment);                   
                }
            } catch (error) {
                console.error('Error downloading attachment:', error);
            }
        },
        async downloadFromUrl(attachment) {
            try {
                const fileName = this.getFileName(attachment);
                const fileUrl = attachment.filePath;
                const response = await fetch(fileUrl);

                if (!response.ok) {
                    throw new Error(`HTTP error! status: ${response.status}`);
                }
                const blob = await response.blob();
                const url = window.URL.createObjectURL(blob);
                const link = document.createElement('a');
                link.href = url;
                link.download = fileName;
                link.style.display = 'none';
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
                setTimeout(() => {
                    window.URL.revokeObjectURL(url);
                }, 100);

                console.log(`File downloaded: ${fileName} (${blob.size} bytes)`);
                return true;
            } catch (error) {
                console.error('Error in downloadFromUrl:', error);
                const link = document.createElement('a');
                link.href = attachment.filePath;
                link.download = this.getFileName(attachment);
                link.target = '_blank';
                link.style.display = 'none';
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
                return true;
            }
        },
        async downloadBase64File(attachment) {
            try {
                const fileName = this.getFileName(attachment);
                const base64String = attachment.filePath;
                const mimeType = attachment.mimeType || 'application/octet-stream';
                let cleanBase64 = base64String;
                if (base64String.includes(',')) {
                    cleanBase64 = base64String.split(',')[1];
                }
                const binaryString = atob(cleanBase64);
                const bytes = new Uint8Array(binaryString.length);
                for (let i = 0; i < binaryString.length; i++) {
                    bytes[i] = binaryString.charCodeAt(i);
                }          
                const blob = new Blob([bytes], { type: mimeType });
                const url = window.URL.createObjectURL(blob);
                const link = document.createElement('a');
                link.href = url;
                link.download = fileName;
                link.style.display = 'none';
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
                setTimeout(() => {
                    window.URL.revokeObjectURL(url);
                }, 100);
                console.log(`File downloaded: ${fileName} (${blob.size} bytes)`);
                return true;
            } catch (error) {
                console.error('Error in downloadBase64File:', error);
                throw error;
            }
        },
        async downloadAllAttachments() {
            try {
                if (this.attachments.length === 0) return;
                if (this.attachments.length === 1) {
                    await this.downloadAttachment(this.attachments[0], 0);
                    return;
                }
            } catch (error) {
                console.error('Error downloading all attachments:', error);
            }
        },
        removeAttachment(item, index) {
            this.confirmR(
                this.$t("Are you sure you want to remove this attachment?"),
                true,
                `${this.$t("remove")}  ${this.$t("Field")}`,
                () => {
                    this.attachments.splice(index, 1);
                    this.$emit('attachment-removed', { item, index });
                }
            );
        },
        closeImageViewer() {
            this.showImageViewer = false;
            this.currentImageUrl = '';
            this.currentImageName = '';
        },

        Cancel() {
            this.$parent.showAttachmentAndSacreenPopup = false;
        }
    }
}
</script>
<style scoped>
.card {
    transition: transform 0.2s;
    position: relative;    
}
.card:hover {
    transform: translateY(-2px);
    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
}
.chat-avatar {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
}
.text-purple {
    color: #6f42c1 !important;
}
.modal-lg {
    max-width: 800px;
}
.modal-xl {
    max-width: 95%;
}
.img-fluid {
    max-height: 70vh;
    object-fit: contain;
}
.btn-close-danger {
    background: none;
    border: none;
    cursor: pointer;
    font-size: 1rem;
}
.btn-close-danger:hover {
    background-color: rgba(220, 53, 69, 0.3);
}
.modal-body h6.card-title.text-truncate {
    width: 100%;
    text-align: center;
    max-width: 151px;
    margin: 0 auto;
}
.modal-body .img-icons img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}
.modal-body .btn-close.btn-close-danger{
        width: 26px;
    height: 26px;
    line-height: 13px;
        position: absolute;
    top: 8px;
    right: 8px;
    z-index: 1;
    background-color: rgba(220, 53, 69, 0.2);
    padding: 0px;
    border-radius: 50%;
    opacity: 0.8;
    transition: opacity 0.2s;
}
</style>