                    vm.file = evt[i];
                }
                const formData = new FormData();
                formData.append('file', vm.file);
                await DataService.UploadImageFile(formData).then(response => {
                    if (response.data.status == "1") {
                        vm.filePath = response.data.filePath;
                    }
                }).catch(err => {
                    console.log(err);
                })
            }
            catch (ex) {
                console.error("Error processing attachments:", ex);
            }
