        CheckListData: async function () {
            var vm = this;
            var url = `ModuleName=Project&TaskId=${vm.projectdata.task_id}`
            await DataService.GetAssociateChecklist(url).then((response) => {
                if (response.data.result.Data != null && response.data.result.Data.length > 0) {
                    vm.TaskCheckList = response.data.result.Data;
                }
                else {
                    vm.TaskCheckList = [];

                }
            });
            vm.isLoading = false;
        },
        OpenchecklistItem: function (itm) {
            var vm = this;
            vm.CheckListitemData = itm;
            vm.IsCheckListPreview = true;
            vm.TaskId = vm.projectdata.task_id;
        },
        DeleteChecklist: function (itm) {
            var vm = this;
            vm.confirmR(vm.$t("DeleteChecklistAndItems"), true, (vm.$t("Delete") + "  " + vm.$t("Checklist")), function () {
                vm.projectdata.task_id;
                itm.checklist_id;
                var url = `TaskId=${vm.projectdata.task_id}&ChecklistId=${itm.checklist_id}`;
                DataService.DeleteChecklistAndItems(url).then(function (response) {
                    if (response.data.status == "Success") {
                        vm.CheckListData();
                        vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Checklist')]), "success", true, vm.$t("Alert"));
                        vm.isLoading = false;
                    }
                    else {
                        vm.ShowAlert(vm.$t('DeleteError'), "warning", true, vm.$t('Alert'));
                    }
                });
            });
        },
        GetChecklistItems: function (itm, index) {
            var vm = this;
            var url = `ChecklistId=${itm.checklist_id}`;
            vm.activeIndex = this.activeIndex === index ? null : index;
            DataService.GetChecklistItems(url).then((response) => {
                if (response && response.data.status == "Success") {
                    vm.ItemsData = response.data.result.Data;
                } else {
                    vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", true, vm.$t('Alert'));
                }
            })
        },
        OpenAddTeamUserPopup: function () {
            var vm = this;
            vm.IsAddTeamUser = true;
            vm.ProjectId = vm.projectdata.project_id;
            vm.TaskId = vm.projectdata.task_id;
        },
        AssignedUser(TeamId) {
            this.TeamId = TeamId.TEAM_USER_ID;
            this.IsUser = true;
        },
        isOpen(index) {
            return this.activeIndex === index;
        },
        ShowCompletedCheckListCount(data) {
            let totalCompleted = data.filter(
                item => item.TotalCount === item.AnswerCount
            ).length;
            return totalCompleted;
        },
        DeleteFile(itm){
            var vm = this;
            vm.isLoading = true;
            vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("Team")), function () {
                var postJSON = {
                    ids: itm.FILE_ID,
                    moduleName: 'Project',
                    subModuleCode: "Project_Detail",
                    refCode: 'Delete_Task_File',
                    refId: null
                };
                var objectPostString = JSON.stringify(postJSON);
                DataService.CommonCommonDelete(objectPostString).then(function (response) {
                    if (response.data[0].Status == "Success") {
                        vm.GetFilesListing();
                        vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('File')]), "success", true, vm.$t("Alert"));
                    }
                    else {
                        vm.ShowAlert(vm.$t('DeleteError'), "warning", true, vm.$t('Alert'));
                    }

                });

            });
            vm.isLoading = false;
        },
        commonDeleteData: function (itm) {
            var vm = this;
            vm.isLoading = true;
            vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("Team")), function () {
                var postJSON = {
                    ids: itm.TEAM_TASK_ID,
                    moduleName: 'Project',
                    subModuleCode: "Project_Detail",
                    refCode: 'TALYGEN_TEAM_TASK',
                    refId: null
                };
                var objectPostString = JSON.stringify(postJSON);
                DataService.CommonCommonDelete(objectPostString).then(function (response) {
                    if (response.data[0].Status == "Success") {
                        if (itm.ROLE_TYPE = 'Team') {
                            vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t(vm.TabsArray.find(t => t.displayCode === "PROJECT_TEAM")?.displayName || 'Team')]), "success", true, vm.$t("Alert"));
                        }
                        else {
                            vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t(vm.TabsArray.find(t => t.displayCode === "PROJECT_TEAM")?.displayName || 'Team')]), "success", true, vm.$t("Alert"));
                        }
                        vm.$emit('callbackfunction');
                        vm.GetUserTeamData();
                    }
                    else {
                        vm.ShowAlert(vm.$t('DeleteError'), "warning", true, vm.$t('Alert'));
                    }

                });

            });
            vm.isLoading = false;
        }
    }
}
</script>
